    <text x="95" y="155" fill="#fbbf24" font-size="13" font-weight="700" text-anchor="middle">2026.1.29</text>
    <text x="95" y="135" fill="#d4d4d8" font-size="13" text-anchor="middle">Revised Act passes Assembly</text>
    <circle cx="270" cy="190" r="7" fill="#fbbf24"/>
