    <text x="270" y="230" fill="#fbbf24" font-size="13" font-weight="700" text-anchor="middle">2026.6.25</text>
    <text x="270" y="250" fill="#d4d4d8" font-size="13" text-anchor="middle">Decree clears Cabinet meeting</text>
    <circle cx="445" cy="190" r="8" fill="#a78bfa"/>
